@namespace sv_9d48e8916f134f5f814e27003087f70b.Components.Pages.Catalog

<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Categories</label>
        @if (Categories.Count == 0)
        {
            <p class="text-muted small">No categories available</p>
        }
        else
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input"
                           type="checkbox"
                           id="@($"cat-{category}")"
                           checked="@(_selectedCategories.Contains(category))"
                           @onchange="@(e => ToggleCategory(category, (bool)(e.Value ?? false)))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm"
                   placeholder="Min" min="0" step="0.01"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm"
                   placeholder="Max" min="0" step="0.01"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@_inStockOnly"
                   @onchange="@(e => _inStockOnly = (bool)(e.Value ?? false))" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@namespace sv_9d48e8916f134f5f814e27003087f70b.Components.Pages.Catalog

<div class="d-flex justify-content-between align-items-center flex-wrap gap-2 mb-3">
    <div class="d-flex align-items-center gap-2">
        <label class="form-label mb-0 fw-semibold" for="sortSelect">Sort by:</label>
        <select id="sortSelect" class="form-select form-select-sm" style="width: auto;"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <span class="text-muted small">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @start–@end of @TotalCount products</text>
        }
        else
        {
            <text>No products found</text>
        }
    </span>
</div>

@code {
    [Parameter] public string SortBy { get; set; } = "price_asc";
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int Page { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_9d48e8916f134f5f814e27003087f70b.Components.Pages.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" disabled="@(Page <= 1)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Page - 1))">
                    Previous
                </button>
            </li>

            @foreach (var pageNum in GetPageNumbers())
            {
                <li class="page-item @(pageNum == Page ? "active" : "")">
                    <button class="page-link"
                            @onclick="@(() => OnPageChanged.InvokeAsync(pageNum))">
                        @pageNum
                    </button>
                </li>
            }

            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" disabled="@(Page >= TotalPages)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Page + 1))">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; }
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int startPage = Math.Max(1, Page - maxVisible / 2);
        int endPage = Math.Min(TotalPages, startPage + maxVisible - 1);
        startPage = Math.Max(1, endPage - maxVisible + 1);

        return Enumerable.Range(startPage, endPage - startPage + 1);
    }
}

@page "/catalog"
@namespace sv_9d48e8916f134f5f814e27003087f70b.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    <!-- Sidebar filters -->
    <div class="col-md-3 mb-3">
        <CatalogFilters Categories="_categories"
                        OnFilterApplied="HandleFilterApplied" />
    </div>

    <!-- Main content -->
    <div class="col-md-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
                <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryAsync">Retry</button>
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height: 200px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is not null && _result.Items.Count > 0)
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_result.Page"
                            PageSize="_result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination Page="_result.Page"
                               TotalCount="_result.TotalCount"
                               PageSize="_result.PageSize"
                               OnPageChanged="HandlePageChanged" />
        }
        else
        {
            <div class="text-center py-5 text-muted">
                <p class="fs-5">No products found</p>
                <p>Try adjusting your filters.</p>
            </div>
        }
    </div>
</div>

@code {
    private const int DefaultPageSize = 12;

    private List<string> _categories = [];
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, DefaultPageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = categoriesTask.Result;
            _result = searchTask.Result;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, DefaultPageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        await Task.CompletedTask;
    }

    private async Task RetryAsync() => await LoadDataAsync();
}

